class Solution {
    public int numRollsToTarget(int n, int k, int target) {
        final int MOD = (int)1e9 + 7;
        int[][] dp = new int[n + 1][target + 1];
        dp[0][0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= target; j++) {
                for (int m = 1; m <= Math.min(j, k); m++) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - m]) % MOD;
                }
            }
        }
        return dp[n][target];
    }
}
